class Solution:
    def numMatchingSubseq(self, s, words):
        from collections import defaultdict
        waiting = defaultdict(list)
        for w in words:
            waiting[w[0]].append((w, 0))
        count = 0
        for ch in s:
            bucket = waiting[ch]
            waiting[ch] = []
            for w, i in bucket:
                j = i + 1
                if j == len(w):
                    count += 1
                else:
                    waiting[w[j]].append((w, j))
        return count

