var numMatchingSubseq = function(s, words) {
    const waiting = new Map();
    const add = (ch, item) => {
        if (!waiting.has(ch)) waiting.set(ch, []);
        waiting.get(ch).push(item);
    };
    for (const w of words) add(w[0], [w, 0]);
    let count = 0;
    for (const ch of s) {
        const bucket = waiting.get(ch);
        if (!bucket) continue;
        waiting.set(ch, []);
        for (const [w, i] of bucket) {
            const j = i + 1;
            if (j === w.length) count++;
            else add(w[j], [w, j]);
        }
    }
    return count;
};
